// FaqData — 唯一の真実のソース（Single Source of Truth）としての FAQ データ。
//
// このデータは2か所から参照されます:
//   1. FAQ.jsx          … ページ上の可視 FAQ（dt/dd）として描画
//   2. build.mjs        … FAQPage の JSON-LD（構造化データ）を自動生成
//
// 両者が同じデータを使うため、「画面の表示内容」と「構造化データ」が
// 構造的に必ず一致します（Google は FAQ 構造化データが可視コンテンツと
// 一致することを要求しており、AI/LLM 回答エンジンの誤引用も防ぎます）。
//
// `a` は構造化データにそのまま使われるプレーンテキストの回答。
// `links` は回答の下に表示する補足リンク（JSON-LD には含めない）。
window.FAQ_DATA = [{
  q: "Androidのクローズドテストとは何ですか？",
  a: "Google Play Consoleで個人アカウントがアプリを本番公開（製品版リリース）する前に必須となるテストです。テスターさんの確保が、個人開発者にとって大きな壁となります。",
  links: [{
    label: "紹介記事①",
    url: "https://qiita.com/AndroidClosedJP/items/4f831238e1fcd2f0b693"
  }]
}, {
  q: "Androidクローズドテスト攻略組への参加は無料ですか？",
  a: "はい。テスターの募集・参加・質問まで、すべて完全無料です。お金ではなく、開発者さん同士の相互協力で成り立っています。",
  links: [{
    label: "紹介記事②",
    url: "https://note.com/androidclosed_jp/n/nb4a3300b5f3d"
  }]
}, {
  q: "どうすれば参加できますか？",
  a: "本コミュニティのDiscordサーバーに参加し、テスター募集・参加のやり取りを行うだけで利用を始められます。",
  links: []
}, {
  q: "テスターは何人、何日間必要ですか？",
  a: "Google Playの要件は、テスター12人以上が14日間（2週間）継続してテストに関与していることです。本コミュニティではメンバー同士が相互にテスターになることで、この条件を無料で満たせます。",
  links: [{
    label: "Googleグループの設定",
    url: "https://qiita.com/AndroidClosedJP/items/63b0c58c4f10d248e18b"
  }]
}, {
  q: "アプリ開発の初心者でも参加できますか？",
  a: "はい。これからアプリ開発に挑戦する方も歓迎しています。つまずいたときに経験者へ質問できる、相談・質問フォーラムも用意しています。",
  links: [{
    label: "相談質問例①",
    url: "https://note.com/androidclosed_jp/n/n9fd0315f815e"
  }]
}, {
  q: "テスターになるのは難しいですか？",
  a: "いいえ、簡単です。リンクからアプリをインストールするだけです。あとはアプリを起動して率直に思ったことを開発者さんに伝えるだけです。あとは14日間だけアプリをインストールしたままにしておけばテスター完了です。",
  links: [{
    label: "テスターの心得",
    url: "https://note.com/androidclosed_jp/n/n4ce1755debf9"
  }, {
    label: "Googleグループへの参加",
    url: "https://qiita.com/AndroidClosedJP/items/55b276df9ece3372d79b"
  }]
}];

